// ❌ BAD - Seeding without explicit PK; EF cannot track or diff this data
builder.HasData(new Category { Name = "Electronics" }); // Id not set - throws

// ✅ GOOD - Explicit PK in IEntityTypeConfiguration keeps seed data co-located with config
public class CategoryConfig : IEntityTypeConfiguration<Category>
{
    public void Configure(EntityTypeBuilder<Category> builder)
    {
        builder.HasKey(c => c.Id);
        builder.Property(c => c.Name).HasMaxLength(100).IsRequired();

        builder.HasData(
            new Category { Id = 1, Name = "Electronics" },
            new Category { Id = 2, Name = "Books" },
            new Category { Id = 3, Name = "Clothing" });
    }
}

// ❌ BAD - Annotations on the entity couple domain to EF; can't express composite keys
public class OrderItem
{
    [Key] // cannot express composite key with this alone
    public int OrderId { get; set; }
    [Key]
    public int ProductId { get; set; }
    [Required]
    [MaxLength(500)]
    public string Notes { get; set; } = string.Empty;
}

// ✅ GOOD - Fluent API in IEntityTypeConfiguration; entity stays clean
public class OrderItemConfig : IEntityTypeConfiguration<OrderItem>
{
    public void Configure(EntityTypeBuilder<OrderItem> builder)
    {
        builder.HasKey(i => new { i.OrderId, i.ProductId }); // composite key
        builder.Property(i => i.Notes).HasMaxLength(500).IsRequired();
    }
}

// ❌ BAD - No explicit delete behavior; SQL Server rejects cascade cycles
public class OrderConfig : IEntityTypeConfiguration<Order>
{
    public void Configure(EntityTypeBuilder<Order> builder)
    {
        builder.HasMany(o => o.Items).WithOne(i => i.Order); // missing OnDelete
    }
}

// ✅ GOOD - Explicit FK, delete behavior, and join entity for payload many-to-many
public class OrderConfig : IEntityTypeConfiguration<Order>
{
    public void Configure(EntityTypeBuilder<Order> builder)
    {
        builder.HasMany(o => o.Items)
               .WithOne(i => i.Order)
               .HasForeignKey(i => i.OrderId)
               .IsRequired()
               .OnDelete(DeleteBehavior.Cascade);
    }
}

public class EnrolmentConfig : IEntityTypeConfiguration<Enrolment>
{
    public void Configure(EntityTypeBuilder<Enrolment> builder)
    {
        builder.HasKey(e => new { e.StudentId, e.CourseId });
        builder.Property(e => e.EnrolledAt).IsRequired();
        builder.HasOne(e => e.Student).WithMany(s => s.Enrolments).HasForeignKey(e => e.StudentId);
        builder.HasOne(e => e.Course).WithMany(c => c.Enrolments).HasForeignKey(e => e.CourseId);
    }
}

// ❌ BAD - MigrateAsync at startup races across multiple pods in Kubernetes
public static async Task Main(string[] args)
{
    var app = CreateApplication(args);
    using var scope = app.Services.CreateScope();
    var ctx = scope.ServiceProvider.GetRequiredService<AppDbContext>();
    await ctx.Database.MigrateAsync(); // 3 pods all run this simultaneously
    await app.RunAsync();
}

// ✅ GOOD - Gate to dev only; use idempotent script in CI/CD for production
public static async Task Main(string[] args)
{
    var app = CreateApplication(args);
    if (app.Environment.IsDevelopment())
    {
        using var scope = app.Services.CreateScope();
        var ctx = scope.ServiceProvider.GetRequiredService<AppDbContext>();
        await ctx.Database.MigrateAsync();
    }
    await app.RunAsync();
    // Production: dotnet ef migrations script --idempotent -o deploy/migrate.sql
}

// ❌ BAD - No concurrency token; last writer silently wins and overwrites other changes
public class Reservation
{
    public int Id { get; set; }
    public string SeatNumber { get; set; } = string.Empty;
    // No RowVersion - two agents can book the same seat simultaneously
}

// ✅ GOOD - RowVersion token; EF detects conflict and throws for the slower writer
public class Reservation
{
    public int Id { get; set; }
    public string SeatNumber { get; set; } = string.Empty;
    public byte[] RowVersion { get; set; } = Array.Empty<byte>();
}

// Config
builder.Property(r => r.RowVersion).IsRowVersion();

// Service
public async Task BookSeatAsync(BookingDto dto)
{
    var reservation = await ctx.Reservations.FindAsync(dto.ReservationId);
    reservation!.SeatNumber = dto.SeatNumber;
    ctx.Entry(reservation).Property(r => r.RowVersion).OriginalValue = dto.RowVersion;
    try { await ctx.SaveChangesAsync(); }
    catch (DbUpdateConcurrencyException) { throw new ConflictException("Seat already taken."); }
}

// ❌ BAD - Adding NOT NULL column to a populated table without backfill; will fail at runtime
protected override void Up(MigrationBuilder migrationBuilder)
{
    migrationBuilder.AddColumn<bool>(
        name: "IsVerified",
        table: "Customers",
        nullable: false); // existing rows have no value - DB rejects this
}

// ✅ GOOD - Add nullable, backfill existing rows, then make NOT NULL in one atomic migration
protected override void Up(MigrationBuilder migrationBuilder)
{
    migrationBuilder.AddColumn<bool>(
        name: "IsVerified",
        table: "Customers",
        nullable: true);

    migrationBuilder.Sql("UPDATE Customers SET IsVerified = 0 WHERE IsVerified IS NULL");

    migrationBuilder.AlterColumn<bool>(
        name: "IsVerified",
        table: "Customers",
        nullable: false,
        defaultValue: false);
}

protected override void Down(MigrationBuilder migrationBuilder)
{
    migrationBuilder.DropColumn(name: "IsVerified", table: "Customers");
}

// ❌ BAD - Modeling address as a separate entity with its own DbSet and surrogate key
public class Address
{
    public int Id { get; set; } // unnecessary surrogate key for a value object
    public string Street { get; set; } = string.Empty;
    public string City { get; set; } = string.Empty;
}

// ✅ GOOD - Owned entity: address columns live in the Orders table, no independent key
public class OrderConfig : IEntityTypeConfiguration<Order>
{
    public void Configure(EntityTypeBuilder<Order> builder)
    {
        builder.OwnsOne(o => o.ShippingAddress, addr =>
        {
            addr.Property(a => a.Street).HasMaxLength(200).IsRequired();
            addr.Property(a => a.City).HasMaxLength(100).IsRequired();
            addr.Property(a => a.PostCode).HasMaxLength(20).IsRequired();
        });

        builder.OwnsMany(o => o.LineItems, item =>
        {
            item.WithOwner().HasForeignKey("OrderId");
            item.Property(i => i.Quantity).IsRequired();
            item.Property(i => i.UnitPrice).HasColumnType("decimal(18,2)");
        });
    }
}
